sql:
SELECT AVG(estimated_effort) AS average_effort
FROM issues
WHERE t_bug = 1;

SELECT COUNT(issue_id) 
FROM issues 
WHERE issue_id NOT IN (SELECT issue_id FROM issue_assignments);
